mapper.delete:
DELETE FROM public.lostark_calendar_schedules
WHERE week_start_date = #{weekStartDate}
  AND week_end_date = #{weekEndDate}

mapper.select:
SELECT id, week_start_date, week_end_date, category_name, contents_name, contents_icon, min_item_level, location, start_time_kst, start_date, start_hhmm, slot_hhmm, rewards, raw_content, is_active, created_at, updated_at
FROM public.lostark_calendar_schedules
WHERE is_active = true
  AND start_time_kst >= #{startDateTime}
  AND start_time_kst < #{endDateTime}
ORDER BY start_time_kst ASC

SELECT id, week_start_date, week_end_date, category_name, contents_name, contents_icon, min_item_level, location, start_time_kst, start_date, start_hhmm, slot_hhmm, rewards, raw_content, is_active, created_at, updated_at
FROM public.lostark_calendar_schedules
WHERE is_active = true
  AND start_time_kst >= #{startTime}
  AND start_time_kst < #{endTime}
ORDER BY start_time_kst, slot_hhmm, category_name, contents_name
